using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsProperties()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.AreEqual(2, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list.ToList());
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "First page has no previous")]
        [DataRow(2, true, DisplayName = "Second page has previous")]
        [DataRow(3, true, DisplayName = "Third page has previous")]
        public void HasPreviousPage_ReturnsExpected(int pageIndex, bool expected)
        {
            var list = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

            Assert.AreEqual(expected, list.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "First of 3 pages has next")]
        [DataRow(3, 3, false, DisplayName = "Last page has no next")]
        [DataRow(2, 3, true, DisplayName = "Middle page has next")]
        public void HasNextPage_ReturnsExpected(int pageIndex, int totalPages, bool expected)
        {
            // pageSize=10, count = totalPages*10 to produce correct TotalPages
            var list = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);

            Assert.AreEqual(expected, list.HasNextPage);
        }

        [TestMethod]
        public void TotalPages_RoundsUp()
        {
            // 11 items, page size 5 => ceil(11/5) = 3
            var list = new PaginatedList<int>(new List<int>(), 11, 1, 5);

            Assert.AreEqual(3, list.TotalPages);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, page.PageIndex);
            Assert.AreEqual(3, page.TotalPages); // ceil(25/10) = 3
            Assert.AreEqual(10, page.Count);
            Assert.AreEqual(11, page.First()); // second page starts at 11
            Assert.AreEqual(20, page.Last());
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page = PaginatedList<int>.Create(source, 3, 10);

            Assert.AreEqual(5, page.Count);
            Assert.AreEqual(21, page.First());
            Assert.AreEqual(25, page.Last());
        }

        [TestMethod]
        public void Create_SinglePage_BothFlagsAreFalse()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var page = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, page.TotalPages);
            Assert.IsFalse(page.HasPreviousPage);
            Assert.IsFalse(page.HasNextPage);
        }
    }
}

