using System;
using System.Collections.Generic;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class ModelTests
    {
        // --- Person / FullName ---

        [TestMethod]
        [DataRow("Smith", "John", "Smith, John")]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary")]
        [DataRow("Li", "Yan", "Li, Yan")]
        public void Person_FullName_ReturnsConcatenation(string lastName, string firstName, string expected)
        {
            var student = new Student { LastName = lastName, FirstMidName = firstName };
            Assert.AreEqual(expected, student.FullName);
        }

        // --- Student ---

        [TestMethod]
        public void Student_EnrollmentDate_CanBeSet()
        {
            var date = new DateTime(2023, 9, 1);
            var student = new Student { EnrollmentDate = date };

            Assert.AreEqual(date, student.EnrollmentDate);
        }

        [TestMethod]
        public void Student_Enrollments_DefaultsToNull()
        {
            var student = new Student();
            Assert.IsNull(student.Enrollments);
        }

        // --- Instructor ---

        [TestMethod]
        public void Instructor_HireDate_CanBeSet()
        {
            var date = new DateTime(2000, 1, 15);
            var instructor = new Instructor { HireDate = date };

            Assert.AreEqual(date, instructor.HireDate);
        }

        [TestMethod]
        public void Instructor_FullName_WorksViaPerson()
        {
            var instructor = new Instructor { LastName = "Harui", FirstMidName = "Roger" };
            Assert.AreEqual("Harui, Roger", instructor.FullName);
        }

        // --- Course ---

        [TestMethod]
        public void Course_Properties_SetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/images/chem.png"
            };

            Assert.AreEqual(1050, course.CourseID);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.AreEqual(3, course.Credits);
            Assert.AreEqual(1, course.DepartmentID);
            Assert.AreEqual("/images/chem.png", course.TeachingMaterialImagePath);
        }

        // --- Department ---

        [TestMethod]
        public void Department_Properties_SetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 5,
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 3
            };

            Assert.AreEqual(5, dept.DepartmentID);
            Assert.AreEqual("Mathematics", dept.Name);
            Assert.AreEqual(100000m, dept.Budget);
            Assert.AreEqual(3, dept.InstructorID);
        }

        [TestMethod]
        public void Department_InstructorID_CanBeNull()
        {
            var dept = new Department { InstructorID = null };
            Assert.IsNull(dept.InstructorID);
        }

        // --- Enrollment ---

        [TestMethod]
        public void Enrollment_Grade_IsNullable()
        {
            var enrollment = new Enrollment();
            Assert.IsNull(enrollment.Grade);
        }

        [TestMethod]
        [DataRow(Grade.A)]
        [DataRow(Grade.B)]
        [DataRow(Grade.C)]
        [DataRow(Grade.D)]
        [DataRow(Grade.F)]
        public void Enrollment_Grade_CanBeSet(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.AreEqual(grade, enrollment.Grade);
        }

        // --- CourseAssignment ---

        [TestMethod]
        public void CourseAssignment_Properties_SetCorrectly()
        {
            var ca = new CourseAssignment { InstructorID = 1, CourseID = 1050 };

            Assert.AreEqual(1, ca.InstructorID);
            Assert.AreEqual(1050, ca.CourseID);
        }

        // --- OfficeAssignment ---

        [TestMethod]
        public void OfficeAssignment_Properties_SetCorrectly()
        {
            var oa = new OfficeAssignment { InstructorID = 2, Location = "Smith 17" };

            Assert.AreEqual(2, oa.InstructorID);
            Assert.AreEqual("Smith 17", oa.Location);
        }

        // --- Notification ---

        [TestMethod]
        public void Notification_Properties_SetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student created",
                CreatedAt = now,
                CreatedBy = "admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.AreEqual(1, notification.Id);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual(now, notification.CreatedAt);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void Notification_ReadAt_CanBeSet()
        {
            var readTime = DateTime.Now;
            var notification = new Notification { IsRead = true, ReadAt = readTime };

            Assert.IsTrue(notification.IsRead);
            Assert.AreEqual(readTime, notification.ReadAt);
        }

        // --- ErrorViewModel ---

        [TestMethod]
        [DataRow(null, false, DisplayName = "Null RequestId => ShowRequestId false")]
        [DataRow("", false, DisplayName = "Empty RequestId => ShowRequestId false")]
        [DataRow("abc-123", true, DisplayName = "Non-empty RequestId => ShowRequestId true")]
        public void ErrorViewModel_ShowRequestId_ReturnsExpected(string? requestId, bool expected)
        {
            var vm = new ErrorViewModel { RequestId = requestId! };
            Assert.AreEqual(expected, vm.ShowRequestId);
        }

        // --- EntityOperation enum ---

        [TestMethod]
        public void EntityOperation_HasExpectedValues()
        {
            Assert.AreEqual(0, (int)EntityOperation.CREATE);
            Assert.AreEqual(1, (int)EntityOperation.UPDATE);
            Assert.AreEqual(2, (int)EntityOperation.DELETE);
        }

        // --- View Models ---

        [TestMethod]
        public void AssignedCourseData_Properties_SetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.AreEqual(1050, data.CourseID);
            Assert.AreEqual("Chemistry", data.Title);
            Assert.IsTrue(data.Assigned);
        }

        [TestMethod]
        public void EnrollmentDateGroup_Properties_SetCorrectly()
        {
            var date = new DateTime(2023, 9, 1);
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };

            Assert.AreEqual(date, group.EnrollmentDate);
            Assert.AreEqual(5, group.StudentCount);
        }

        [TestMethod]
        public void EnrollmentDateGroup_EnrollmentDate_CanBeNull()
        {
            var group = new EnrollmentDateGroup { EnrollmentDate = null };
            Assert.IsNull(group.EnrollmentDate);
        }

        [TestMethod]
        public void InstructorIndexData_Properties_SetCorrectly()
        {
            var instructors = new List<Instructor>();
            var courses = new List<Course>();
            var enrollments = new List<Enrollment>();

            var data = new InstructorIndexData
            {
                Instructors = instructors,
                Courses = courses,
                Enrollments = enrollments
            };

            Assert.AreSame(instructors, data.Instructors);
            Assert.AreSame(courses, data.Courses);
            Assert.AreSame(enrollments, data.Enrollments);
        }
    }
}

