using System;
using System.Linq;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            // Drain any leftover notifications from previous tests (static queue)
            _sut = new NotificationService();
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        public void SendAndReceive_SingleNotification_Works()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "admin");

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("Student", result.EntityType);
            Assert.AreEqual("1", result.EntityId);
            Assert.AreEqual("CREATE", result.Operation);
            Assert.AreEqual("admin", result.CreatedBy);
            Assert.IsFalse(result.IsRead);
            Assert.IsNull(result.ReadAt);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("New Student 'John Doe' has been created", result.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("New Student (ID: 42) has been created", result.Message);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Course 'Physics' has been created")]
        [DataRow(EntityOperation.UPDATE, "Course 'Physics' has been updated")]
        [DataRow(EntityOperation.DELETE, "Course 'Physics' has been deleted")]
        public void SendNotification_GeneratesCorrectMessagePerOperation(EntityOperation operation, string expectedMessage)
        {
            _sut.SendNotification("Course", "101", "Physics", operation, "admin");

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual(expectedMessage, result.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("System", result.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.IsTrue(result.CreatedAt >= before && result.CreatedAt <= after);
        }

        [TestMethod]
        public void SendAndReceive_MultipleNotifications_FifoOrder()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", EntityOperation.UPDATE);
            _sut.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();
            var third = _sut.ReceiveNotification();

            Assert.AreEqual("Student", first!.EntityType);
            Assert.AreEqual("Course", second!.EntityType);
            Assert.AreEqual("Department", third!.EntityType);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op, but should not throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            _sut.Dispose();
            _sut.Dispose(); // should not throw
        }

        [TestMethod]
        public void SendNotification_NullDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "5", null, EntityOperation.UPDATE);

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("Student (ID: 5) has been updated", result.Message);
        }

        [TestMethod]
        public void SendNotification_EmptyDisplayName_UsesIdInMessage()
        {
            _sut.SendNotification("Student", "5", "", EntityOperation.DELETE);

            var result = _sut.ReceiveNotification();

            Assert.IsNotNull(result);
            Assert.AreEqual("Student (ID: 5) has been deleted", result.Message);
        }
    }
}

