using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests : IDisposable
    {
        private SchoolContext _context = null!;
        private HomeController _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new HomeController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        public void Dispose() => Cleanup();

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _sut.Index();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentGroups()
        {
            var result = _sut.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            // Seeded data has 1 student with EnrollmentDate 2010-09-01
            Assert.IsTrue(model.Count > 0);
            Assert.AreEqual(1, model[0].StudentCount);
        }

        [TestMethod]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            var emptyContext = TestDbContextFactory.Create();
            using var controller = new HomeController(emptyContext);
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };

            var result = controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            var result = _sut.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", _sut.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _sut.Error();

            Assert.IsInstanceOfType<ViewResult>(result);
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessage()
        {
            var result = _sut.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", _sut.ViewBag.Message);
        }
    }
}

