using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests : IDisposable
    {
        private SchoolContext _context = null!;
        private StudentsController _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _sut = new StudentsController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _sut.TempData = new TempDataDictionary(
                _sut.ControllerContext.HttpContext,
                new SessionStateTempDataProvider()); // requires session, but we use a fallback
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        public void Dispose() => Cleanup();

        // --- Index ---

        [TestMethod]
        public void Index_NoParams_ReturnsViewWithStudents()
        {
            var result = _sut.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_SearchString_FiltersStudents()
        {
            // Add a second student for filtering
            _context.Students.Add(new Student
            {
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = new DateTime(2012, 9, 1)
            });
            _context.SaveChanges();

            var result = _sut.Index(null, null, "Alexander", null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchString_ResetsToPage1()
        {
            var result = _sut.Index(null, null, "test", 5) as ViewResult;

            Assert.IsNotNull(result);
            // When searchString is not null, page should be reset to 1
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_SortByNameDesc_ReturnsSortedStudents()
        {
            _context.Students.Add(new Student
            {
                FirstMidName = "Zoe",
                LastName = "Zebra",
                EnrollmentDate = new DateTime(2012, 9, 1)
            });
            _context.SaveChanges();

            var result = _sut.Index("name_desc", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Zebra", model[0].LastName);
        }

        [TestMethod]
        [DataRow("Date", DisplayName = "Sort by date ascending")]
        [DataRow("date_desc", DisplayName = "Sort by date descending")]
        [DataRow("name_desc", DisplayName = "Sort by name descending")]
        [DataRow("", DisplayName = "Default sort")]
        [DataRow(null, DisplayName = "Null sort")]
        public void Index_AllSortOrders_ReturnsView(string? sortOrder)
        {
            var result = _sut.Index(sortOrder, null, null, null) as ViewResult;
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Index_CurrentFilter_UsedWhenSearchStringIsNull()
        {
            _context.Students.Add(new Student
            {
                FirstMidName = "Bob",
                LastName = "Builder",
                EnrollmentDate = new DateTime(2012, 9, 1)
            });
            _context.SaveChanges();

            var result = _sut.Index(null, "Alexander", null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_SetsViewBagProperties()
        {
            _sut.Index("Date", null, "test", null);

            Assert.AreEqual("Date", _sut.ViewBag.CurrentSort);
            Assert.AreEqual("date_desc", _sut.ViewBag.DateSortParm);
            Assert.AreEqual("", _sut.ViewBag.NameSortParm);
            Assert.AreEqual("test", _sut.ViewBag.CurrentFilter);
        }

        [TestMethod]
        public void Index_DefaultSort_SetsCorrectSortParms()
        {
            _sut.Index(null, null, null, null);

            Assert.AreEqual("name_desc", _sut.ViewBag.NameSortParm);
            Assert.AreEqual("Date", _sut.ViewBag.DateSortParm);
        }

        // --- Details ---

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_IncludesEnrollments()
        {
            var result = _sut.Details(1) as ViewResult;

            var student = result!.Model as Student;
            Assert.IsNotNull(student!.Enrollments);
            Assert.AreEqual(1, student.Enrollments.Count);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidModel_RedirectsToIndex()
        {
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _sut.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidDate_ReturnsViewWithError()
        {
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
        }

        [TestMethod]
        public void Create_Post_DateOutOfRange_ReturnsViewWithError()
        {
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Jane",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _sut.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreSame(student, result.Model);
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsView()
        {
            var result = _sut.Edit(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _sut.Edit(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        // --- Edit POST ---

        [TestMethod]
        public void Edit_Post_ValidModel_RedirectsToIndex()
        {
            var student = _context.Students.Find(1)!;
            // Detach the tracked entity first
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = 1,
                FirstMidName = "CarsonUpdated",
                LastName = "Alexander",
                EnrollmentDate = new DateTime(2010, 9, 1)
            };

            var result = _sut.Edit(updatedStudent) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidDate_ReturnsViewWithError()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _sut.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = new DateTime(2010, 9, 1)
            };

            var result = _sut.Edit(student) as ViewResult;

            Assert.IsNotNull(result);
        }

        // --- Delete GET ---

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var result = _sut.Delete(1) as ViewResult;

            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _sut.Delete(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        // --- DeleteConfirmed POST ---

        [TestMethod]
        public void DeleteConfirmed_ValidId_RedirectsToIndex()
        {
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Students.Count());
        }
    }
}

