using System;
using System.IO;
using System.Linq;
using System.Net;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class CoursesControllerTests : IDisposable
    {
        private SchoolContext _context = null!;
        private CoursesController _sut = null!;
        private Mock<IWebHostEnvironment> _mockEnv = null!;
        private Mock<ILogger<CoursesController>> _mockLogger = null!;
        private string _tempDir = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _sut = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, recursive: true);
        }

        public void Dispose() => Cleanup();

        // --- Index ---

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _sut.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Chemistry", model[0].Title);
        }

        // --- Details ---

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _sut.Details(1050) as ViewResult;

            Assert.IsNotNull(result);
            var course = result.Model as Course;
            Assert.IsNotNull(course);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.IsNotNull(course.Department);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDepartmentSelectList()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.DepartmentID);
            var model = result.Model as Course;
            Assert.IsNotNull(model);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 2000,
                Title = "Physics",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _sut.Create(course, null!) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Courses.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2000, DepartmentID = 1 };

            var result = _sut.Create(course, null!) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 3000,
                Title = "Art",
                Credits = 2,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = _sut.Create(course, mockFile) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.IsTrue(course.TeachingMaterialImagePath!.StartsWith("/Uploads/TeachingMaterials/"));
        }

        [TestMethod]
        public void Create_Post_InvalidImageExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 3001,
                Title = "Art",
                Credits = 2,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.txt", "text/plain", 1024);

            var result = _sut.Create(course, mockFile) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_ImageTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 3002,
                Title = "Art",
                Credits = 2,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.png", "image/png", 6 * 1024 * 1024);

            var result = _sut.Create(course, mockFile) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsView()
        {
            var result = _sut.Edit(1050) as ViewResult;

            Assert.IsNotNull(result);
