            Assert.IsNotNull(course);
            Assert.AreEqual("Chemistry", course.Title);
            Assert.IsNotNull(_sut.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _sut.Edit(9999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        // --- Edit POST ---

        [TestMethod]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            // Detach tracked entity
            var existing = _context.Courses.Find(1050)!;
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Advanced Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _sut.Edit(course, null!) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = _sut.Edit(course, null!) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Edit_Post_WithImage_InvalidExtension_ReturnsError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("bad.exe", "application/octet-stream", 1024);

            var result = _sut.Edit(course, mockFile) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Edit_Post_WithImage_TooLarge_ReturnsError()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("big.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = _sut.Edit(course, mockFile) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // --- Delete GET ---

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var result = _sut.Delete(1050) as ViewResult;

            Assert.IsNotNull(result);
            var course = result.Model as Course;
            Assert.IsNotNull(course);
            Assert.AreEqual("Chemistry", course.Title);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        // --- DeleteConfirmed POST ---

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var result = _sut.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Courses.Count());
        }

        // --- Helpers ---

        private static IFormFile CreateMockFormFile(string fileName, string contentType, long length)
        {
            var content = new byte[Math.Min(length, 1024)]; // don't allocate huge buffers
            var stream = new MemoryStream(content);
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.ContentType).Returns(contentType);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.OpenReadStream()).Returns(stream);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return mock.Object;
        }
    }
}

