using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests : IDisposable
    {
        private SchoolContext _context = null!;
        private InstructorsController _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            SeedInstructorData(_context);

            _sut = new InstructorsController(_context);
            _sut.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        private static void SeedInstructorData(SchoolContext context)
        {
            var instructor = new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            context.Instructors.Add(instructor);

            var department = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };
            context.Departments.Add(department);

            var course = new Course
            {
                CourseID = 2021,
                Title = "Composition",
                Credits = 3,
                DepartmentID = 1,
                Enrollments = new List<Enrollment>()
            };
            context.Courses.Add(course);

            context.SaveChanges();

            // Add course assignment after both entities exist
            var ca = new CourseAssignment { InstructorID = 1, CourseID = 2021 };
            context.CourseAssignments.Add(ca);
            context.SaveChanges();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        public void Dispose() => Cleanup();

        // --- Index ---

        [TestMethod]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            var result = _sut.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Instructors.Any());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _sut.Index(1, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
            Assert.IsTrue(model.Courses.Any());
            Assert.AreEqual(1, (int)_sut.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Index_WithInstructorAndCourseId_PopulatesEnrollments()
        {
            // Add a student and enrollment
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 1, 1)
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            _context.Enrollments.Add(new Enrollment
            {
                CourseID = 2021,
                StudentID = student.ID,
                Grade = Grade.A
            });
            _context.SaveChanges();

            var result = _sut.Index(1, 2021) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Enrollments);
        }

        // --- Details ---

        [TestMethod]
        public void Details_ValidId_ReturnsView()
        {
            var result = _sut.Details(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _sut.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _sut.Details(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithCoursesInViewBag()
        {
            var result = _sut.Create() as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.IsNotNull(instructor.CourseAssignments);
            Assert.IsNotNull(_sut.ViewBag.Courses);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Roger",
                LastName = "Harui",
                HireDate = new DateTime(1998, 7, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _sut.Create(instructor, null!) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = new DateTime(2002, 7, 6)
            };

            var result = _sut.Create(instructor, new[] { "2021" }) as RedirectToActionResult;

            Assert.IsNotNull(result);
            var saved = _context.Instructors.Where(i => i.LastName == "Fakhouri").Single();
            // Load course assignments
            _context.Entry(saved).Collection(i => i.CourseAssignments).Load();
            Assert.AreEqual(1, saved.CourseAssignments.Count);
        }

        [TestMethod]
        public void Create_Post_InvalidModel_ReturnsView()
        {
            _sut.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _sut.Create(instructor, null!) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.Courses);
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsView()
        {
            var result = _sut.Edit(1) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(_sut.ViewBag.Courses);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _sut.Edit(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        // --- Delete GET ---

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var result = _sut.Delete(1) as ViewResult;

            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _sut.Delete(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _sut.Delete(999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        // --- DeleteConfirmed POST ---

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndNullsDepartmentAdmin()
        {
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, _context.Instructors.Count());

            // Department should have InstructorID set to null
            var dept = _context.Departments.Find(1);
            Assert.IsNotNull(dept);
            Assert.IsNull(dept.InstructorID);
        }
    }
}

