using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class SchoolContextTests
    {
        [TestMethod]
        public void SchoolContext_CanCreateAndQuery_Students()
        {
            using var context = TestDbContextFactory.Create();

            context.Students.Add(new Student
            {
                FirstMidName = "Test",
                LastName = "User",
                EnrollmentDate = new DateTime(2023, 1, 1)
            });
            context.SaveChanges();

            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual("User", context.Students.First().LastName);
        }

        [TestMethod]
        public void SchoolContext_CanCreateAndQuery_Instructors()
        {
            using var context = TestDbContextFactory.Create();

            context.Instructors.Add(new Instructor
            {
                FirstMidName = "Prof",
                LastName = "Smith",
                HireDate = new DateTime(2000, 1, 1)
            });
            context.SaveChanges();

            Assert.AreEqual(1, context.Instructors.Count());
        }

        [TestMethod]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.Create();

            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Prof",
                HireDate = new DateTime(2000, 1, 1)
            };
            context.Instructors.Add(instructor);

            var department = new Department
            {
                Name = "Test",
                Budget = 100000m,
                StartDate = new DateTime(2007, 1, 1)
            };
            context.Departments.Add(department);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 101,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = department.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            context.SaveChanges();

            var ca = context.CourseAssignments.First();
            Assert.AreEqual(instructor.ID, ca.InstructorID);
            Assert.AreEqual(course.CourseID, ca.CourseID);
        }

        [TestMethod]
        public void SchoolContext_Enrollment_RelatesStudentAndCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();

            var enrollment = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .First();

            Assert.IsNotNull(enrollment.Student);
