using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsAllData()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.Students.Count());
            Assert.AreEqual(5, context.Instructors.Count());
            Assert.AreEqual(4, context.Departments.Count());
            Assert.AreEqual(7, context.Courses.Count());
            Assert.AreEqual(3, context.OfficeAssignments.Count());
            Assert.AreEqual(8, context.CourseAssignments.Count());
            Assert.AreEqual(11, context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context); // call again

            // Counts should remain the same
            Assert.AreEqual(8, context.Students.Count());
            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_SeedsCorrectStudentNames()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            CollectionAssert.Contains(studentNames, "Alexander");
            CollectionAssert.Contains(studentNames, "Alonso");
            CollectionAssert.Contains(studentNames, "Olivetto");
        }

        [TestMethod]
        public void Initialize_SeedsCoursesWithDepartments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
            var dept = context.Departments.Find(chemistry.DepartmentID);
            Assert.IsNotNull(dept);
            Assert.AreEqual("Engineering", dept.Name);
        }

        [TestMethod]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

